from __future__ import annotations
from typing import TypedDict

class AgentState(TypedDict):
    run_id: str
    messages: list[dict]
    tokens_used: int
    last_error: str | None
    pending_tool_call: dict | None

# ── Pattern 1: simple None-guard ──────────────────────────────────────────────
def log_error(state: AgentState) -> None:
    if state["last_error"] is not None:
        # mypy narrows: state["last_error"] is str here
        print(f"Run {state['run_id']} failed: {state['last_error']}")

# ── Pattern 2: provide a fallback with 'or' ───────────────────────────────────
def token_budget_remaining(state: AgentState, limit: int) -> int:
    used = state["tokens_used"] or 0
    return max(0, limit - used)

# ── Pattern 3: .get() on a TypedDict returns T | None ────────────────────────
def safe_extract_tool_name(call: dict) -> str | None:
    fn = call.get("function")
    if fn is None:
        return None
    return fn.get("name")   # str | None

