from __future__ import annotations
import json
from typing import TypedDict, Literal, Required, NotRequired

# ── Type definitions ──────────────────────────────────────────────────────────
class Message(TypedDict):
    role: str
    content: str

class FunctionCall(TypedDict):
    name: str
    arguments: str  # JSON string

class ToolCall(TypedDict):
    id: str
    type: Literal["function"]
    function: FunctionCall

class AgentState(TypedDict):
    run_id: str
    messages: list[Message]
    tokens_used: int
    last_error: str | None
    active_tool_call: ToolCall | None

# ── State helpers ─────────────────────────────────────────────────────────────
def initial_state(run_id: str, system_prompt: str) -> AgentState:
    return {
        "run_id": run_id,
        "messages": [{"role": "system", "content": system_prompt}],
        "tokens_used": 0,
        "last_error": None,
        "active_tool_call": None,
    }

def append_user(state: AgentState, text: str) -> AgentState:
    state["messages"].append({"role": "user", "content": text})
    return state

def handle_tool_call(state: AgentState, tc: ToolCall) -> dict[str, object]:
    """Dispatch to a registered tool; returns tool result payload."""
    fn_name = tc["function"]["name"]
    try:
        raw_args = tc["function"]["arguments"]
        args: dict[str, object] = json.loads(raw_args)
    except json.JSONDecodeError as exc:
        state["last_error"] = f"Bad tool args: {exc}"
        return {"error": str(exc)}

    # Fake tool registry
    if fn_name == "get_weather":
        city = args.get("city", "unknown")
        return {"temperature": 22, "city": city, "unit": "C"}
    return {"error": f"Unknown tool: {fn_name}"}

def process_response(state: AgentState, response: dict) -> AgentState:
    """Extract assistant message; handle optional tool_calls key."""
    choices = response.get("choices", [])
    if not choices:
        state["last_error"] = "Empty choices in response"
        return state

    msg = choices[0].get("message", {})
    content: str | None = msg.get("content")  # may be None when tool calling
    tool_calls: list[ToolCall] | None = msg.get("tool_calls")

    if tool_calls:
        state["active_tool_call"] = tool_calls[0]
        result = handle_tool_call(state, tool_calls[0])
        state["messages"].append({
            "role": "tool",
            "content": json.dumps(result),
        })
    elif content is not None:
        state["messages"].append({"role": "assistant", "content": content})
    else:
        state["last_error"] = "Response has neither content nor tool_calls"

    usage = response.get("usage") or {}
    state["tokens_used"] += usage.get("total_tokens", 0)
    return state
